    private Node getMiddle(Node head) {
        Node slow = head, fast = head.next;
        while (fast != null && fast.next != null) {
            slow = slow.next; fast = fast.next.next;
        }
        return slow;
    }

    public Node mergeSort(Node head) {
        if (head == null || head.next == null) return head;
        Node mid = getMiddle(head);
        Node right = mid.next;
        mid.next = null; // split list
        Node left = mergeSort(head);
        right = mergeSort(right);
        return mergeTwoSorted(left, right);
    }

    private Node buildList(int... vals) {
        Node dummy=new Node(0),tail=dummy;
        for(int v:vals){tail.next=new Node(v);tail=tail.next;} return dummy.next;
    }
    private String listStr(Node h) {
        StringBuilder sb=new StringBuilder();
        while(h!=null){sb.append(h.val);if(h.next!=null)sb.append("->");h=h.next;} return sb.toString();
    }

    public static void main(String[] args) {
        MergeSortedLists msl = new MergeSortedLists();
        Node l1 = msl.buildList(1, 3, 5);
        Node l2 = msl.buildList(2, 4, 6);
        System.out.println(msl.listStr(msl.mergeTwoSorted(l1, l2)));
        Node unsorted = msl.buildList(4, 2, 1, 3);
        System.out.println(msl.listStr(msl.mergeSort(unsorted)));
    }
}

